class UpdateUserProfile(Mutation):
    class Arguments:
        user_id = String(required=True, description="ID of the user to update")
        username = String(description="New username")
        email = String(description="New email address")
        bio = String(description="New bio text")
        role = String(description="New role (admin only)")
        is_admin = Boolean(description="Admin status (admin only)")
        credits = Int(description="Credit balance (admin only)")
        subscription_tier = String(description="Subscription tier (admin only)")

    user = Field(UserType)
    success = Boolean(required=True)
    message = String(required=True)

    @staticmethod
    def mutate(root, info, user_id, **kwargs):
        # Get authenticated user from context
        authenticated_user = info.context.get("authenticated_user") if hasattr(info.context, "get") else getattr(info.context, "authenticated_user", None)

        if not authenticated_user:
            return UpdateUserProfile(
                user=None,
                success=False,
                message="Authentication required. No authenticated user found in context.",
            )

        auth_user_id = authenticated_user.get("id")
        auth_is_admin = authenticated_user.get("is_admin", False)

        # Check if target user exists
        target_user = USERS_DB.get(user_id)
        if not target_user:
            return UpdateUserProfile(
                user=None,
                success=False,
                message=f"User with ID '{user_id}' not found.",
            )

        # Filter out None values - only process explicitly provided fields
        provided_fields = {k: v for k, v in kwargs.items() if v is not None}

        if not provided_fields:
            return UpdateUserProfile(
                user=None,
                success=False,
                message="No fields provided for update.",
            )

        is_self_update = auth_user_id == user_id

        # Authorization checks
        if not auth_is_admin:
            # Non-admin users can only update their own profile
            if not is_self_update:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Permission denied. You can only update your own profile.",
                )

            # Check if non-admin is trying to modify admin-only fields
            attempted_admin_fields = set(provided_fields.keys()) & ADMIN_ONLY_FIELDS
            if attempted_admin_fields:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message=f"Permission denied. Only admins can modify: {', '.join(sorted(attempted_admin_fields))}.",
                )

        # Validate field values
        if "username" in provided_fields:
            username = provided_fields["username"].strip()
            if not username:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Username cannot be empty.",
                )
            if len(username) < 3:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Username must be at least 3 characters long.",
                )
            if len(username) > 50:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Username must be at most 50 characters long.",
                )
            # Check username uniqueness
            for uid, user_data in USERS_DB.items():
                if uid != user_id and user_data["username"].lower() == username.lower():
                    return UpdateUserProfile(
                        user=None,
                        success=False,
                        message=f"Username '{username}' is already taken.",
                    )
            provided_fields["username"] = username

        if "email" in provided_fields:
            email = provided_fields["email"].strip()
            if not email or "@" not in email or "." not in email.split("@")[-1]:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Invalid email address format.",
                )
            # Check email uniqueness
            for uid, user_data in USERS_DB.items():
                if uid != user_id and user_data["email"].lower() == email.lower():
                    return UpdateUserProfile(
                        user=None,
                        success=False,
                        message=f"Email '{email}' is already in use.",
                    )
            provided_fields["email"] = email

        if "bio" in provided_fields:
            bio = provided_fields["bio"].strip()
            if len(bio) > 500:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Bio must be at most 500 characters long.",
                )
            provided_fields["bio"] = bio

        if "role" in provided_fields:
            role = provided_fields["role"].lower().strip()
            if role not in VALID_ROLES:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message=f"Invalid role '{role}'. Must be one of: {', '.join(sorted(VALID_ROLES))}.",
                )
            provided_fields["role"] = role

        if "credits" in provided_fields:
            credits = provided_fields["credits"]
            if credits < 0:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Credits cannot be negative.",
                )

        if "subscription_tier" in provided_fields:
            tier = provided_fields["subscription_tier"].lower().strip()
            if tier not in VALID_SUBSCRIPTION_TIERS:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message=f"Invalid subscription tier '{tier}'. Must be one of: {', '.join(sorted(VALID_SUBSCRIPTION_TIERS))}.",
                )
            provided_fields["subscription_tier"] = tier

        # Apply updates
        for field, value in provided_fields.items():
            target_user[field] = value

        updated_user = UserType(
            id=target_user["id"],
            username=target_user["username"],
            email=target_user["email"],
            bio=target_user["bio"],
            role=target_user["role"],
            is_admin=target_user["is_admin"],
            credits=target_user["credits"],
            subscription_tier=target_user["subscription_tier"],
        )

        updated_fields_list = ", ".join(sorted(provided_fields.keys()))
        return UpdateUserProfile(
            user=updated_user,
            success=True,
            message=f"Successfully updated fields: {updated_fields_list}.",
        )


class Query(ObjectType):
    user = Field(UserType, user_id=String(required=True))
    me = Field(UserType)
    all_users = graphene.List(UserType)

    @staticmethod
    def resolve_user(root, info, user_id):
        user_data = USERS_DB.get(user_id)
        if user_data:
            return UserType(**user_data)
        return None

    @staticmethod
    def resolve_me(root, info):
        authenticated_user = info.context.get("authenticated_user") if hasattr(info.context, "get") else getattr(info.context, "authenticated_user", None)
        if authenticated_user:
            user_data = USERS_DB.get(authenticated_user["id"])
            if user_data:
                return UserType(**user_data)
        return None

    @staticmethod
    def resolve_all_users(root, info):
        return [UserType(**user_data) for user_data in USERS_DB.values()]


class Mutations(ObjectType):
    update_user_profile = UpdateUserProfile.Field()


schema = Schema(query=Query, mutation=Mutations)


def execute_query(query, context=None, variables=None):
    """Helper function to execute a GraphQL query with context."""
    result = schema.execute(
        query,
        context=context or {},
        variables=variables,
    )
    if result.errors:
        print(f"Errors: {result.errors}")
    if result.data:
        print(f"Data: {result.data}")
    return result


